            aIngress = aIngress + (aOrbiterG ^ RotL64(aOrbiterE, 23U));
            aIngress = aIngress + (aOrbiterD ^ RotL64(aOrbiterJ, 19U));
            aIngress = aIngress + (aOrbiterB ^ RotL64(aOrbiterC, 37U));
