            //
            aOrbiterB = (aWandererG + RotL64(aIngress, 51U)) + 0xD97F41A2ED504F85ULL;
            aOrbiterK = ((aWandererF + RotL64(aScatter, 43U)) + RotL64(aCarry, 51U)) + 0x24F81BE561D9E994ULL;
            aOrbiterD = (aWandererK + RotL64(aCross, 57U)) + 0xEEEA7D055F8694C5ULL;
