            aOrbiterB = RotL64((aOrbiterB * 0x2D92FC48FD5DA3E9ULL), 35U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterJ) + 0x77D8FAF3E90581E1ULL) + aPhaseGOrbiterUpdateSaltD[(((31U - aIndex) + 3U)) & 31];
